import { type ApiPayloadResult } from '@/shared/contracts/http';
import { ApiError } from '@/shared/lib/api-client';
import { logClientError } from '@/shared/utils/observability/client-error-logger';
import { type DatabaseType } from '@/shared/contracts/database';

export const withDbTypeQuery = (endpoint: string, dbType?: DatabaseType): string => {
  if (!dbType) return endpoint;
  return `${endpoint}?type=${encodeURIComponent(dbType)}`;
};

export const toFallbackErrorPayload = <T>(error: unknown): T =>
  ({
    success: false,
    error: error instanceof Error ? error.message : String(error),
  }) as T;

export const wrapInApiPayloadResult = async <T>(promise: Promise<T>): Promise<ApiPayloadResult<T>> => {
  try {
    const data = await promise;
    return { ok: true, payload: data };
  } catch (error) {
    logClientError(error);
    if (error instanceof ApiError) {
      if (error.payload !== undefined && error.payload !== null) {
        return { ok: false, payload: error.payload as T };
      }
      return { ok: false, payload: toFallbackErrorPayload<T>(error) };
    }
    return { ok: false, payload: toFallbackErrorPayload<T>(error) };
  }
};

'use client';

import { EditIcon, Trash2Icon } from 'lucide-react';
import React, { useMemo } from 'react';
import type { DatabaseType } from '@/shared/contracts/database';
import { Button, Card } from '@/shared/ui/primitives.public';
import { StandardDataTablePanel } from '@/shared/ui/templates.public';
import { CompactEmptyState, Pagination } from '@/shared/ui/navigation-and-layout.public';
import { ConfirmModal } from '@/shared/ui/templates/modals';
import { CrudPanelProvider } from '../context/CrudPanelContext';
import { useCrudPanelState } from '../hooks/useCrudPanelState';
import { DatabaseTableSelector } from './crud/DatabaseTableSelector';
import { RowFormModal } from './crud/RowFormModal';
import { formatDatabaseCellValue } from './format-cell-value';
import type { ColumnDef } from '@tanstack/react-table';


export interface CrudPanelProps {
  tableDetails?: { columns: any[] };
  defaultTable?: string;
  dbType?: DatabaseType;
}

interface RowData extends Record<string, unknown> {}

const createActionColumn = (
  setEditingRow: (row: RowData) => void,
  setDeletingRow: (row: RowData) => void
): ColumnDef<RowData> => ({
  id: 'actions',
  header: 'Actions',
  cell: ({ row }) => (
    <div className='flex items-center gap-1'>
      <Button variant='ghost' size='xs' onClick={() => setEditingRow(row.original)} className='rounded p-1 text-gray-400 hover:bg-white/10 hover:text-blue-300' title='Edit row' aria-label='Edit row'>
        <EditIcon className='size-3.5' />
      </Button>
      <Button variant='ghost' size='xs' onClick={() => setDeletingRow(row.original)} className='rounded p-1 text-gray-400 hover:bg-white/10 hover:text-rose-300' title='Delete row' aria-label='Delete row'>
        <Trash2Icon className='size-3.5' />
      </Button>
    </div>
  ),
  size: 80,
});

const createDataColumns = (keys: string[]): ColumnDef<RowData>[] => {
  return keys.map((key) => ({
    accessorKey: key,
    header: key,
    cell: ({ row }) => (
      <span className='font-mono text-xs text-gray-300 truncate block max-w-[200px]' title={formatDatabaseCellValue(row.original[key])}>
        {formatDatabaseCellValue(row.original[key])}
      </span>
    ),
  }));
};

import { useCrudPanelStateContext, useCrudPanelActionsContext } from '../context/CrudPanelContext';

const DataTable = ({
  columnDefs,
  rows,
  isLoadingRows,
  errorMessage,
  successMessage,
  page,
  pageSize,
  totalRows,
}: {
  columnDefs: ColumnDef<RowData>[];
  rows: RowData[];
  isLoadingRows: boolean;
  errorMessage: string | null;
  successMessage: string | null;
  page: number;
  pageSize: number;
  totalRows: number;
}): React.JSX.Element => {
  const { selectedTable } = useCrudPanelStateContext();
  const { setPage, setPageSize } = useCrudPanelActionsContext();

  if (selectedTable === '') {
    return (
      <div className='space-y-4'>
        <Card variant='subtle-compact' padding='sm' className='flex flex-wrap items-center gap-3 bg-card/30 border-border/60'><DatabaseTableSelector /></Card>
        <CompactEmptyState title='No table selected' description='Please select a table.' className='bg-card/40 border-dashed border-border/60 py-20' />
      </div>
    );
  }

  return (
    <StandardDataTablePanel
      columns={columnDefs}
      data={rows}
      isLoading={isLoadingRows}
      maxHeight='50vh'
      stickyHeader
      alerts={
        <>
          {errorMessage !== null && errorMessage !== '' && <div className='px-3 py-2 text-xs bg-red-500/10 text-red-500'>{errorMessage}</div>}
          {successMessage !== null && successMessage !== '' && <div className='px-3 py-2 text-xs bg-emerald-500/10 text-emerald-500'>{successMessage}</div>}
        </>
      }
      filters={<DatabaseTableSelector />}
      footer={
        selectedTable !== '' && !isLoadingRows && rows.length > 0 ? (
          <div className='px-4 pb-2'>
            <Pagination variant='panel' page={page} pageSize={pageSize} totalCount={totalRows} onPageChange={setPage} onPageSizeChange={(size: number) => { setPage(1); setPageSize(size); }} isLoading={isLoadingRows} />
          </div>
        ) : null
      }
      variant='flat'
    />
  );
};

export function CrudPanel(props: CrudPanelProps): React.JSX.Element {
  const {
    selectedTable,
    setSelectedTable,
    page,
    setPage,
    pageSize,
    setPageSize,
    mutationError,
    setMutationError,
    successMessage,
    setSuccessMessage,
    showAddModal,
    setShowAddModal,
    editingRow,
    setEditingRow,
    deletingRow,
    setDeletingRow,
    tableDetail,
    rows,
    totalRows,
    isLoadingRows,
    fetchRows,
    handleAdd,
    handleEdit,
    handleDelete,
    crudMutation,
    tableDetails,
    columns,
    rowsQuery,
  } = useCrudPanelState(props);

  const errorMessage = mutationError ?? (rowsQuery.isError && rowsQuery.error instanceof Error ? rowsQuery.error.message : null);

  const columnDefs = useMemo<ColumnDef<RowData>[]>(() => {
    if (columns.length === 0 && rows.length === 0) return [];

    const actionCol = createActionColumn(setEditingRow, setDeletingRow);
    const keys = rows.length > 0 ? Object.keys(rows[0] ?? {}) : columns.map((c: { name: string }) => c.name);
    const dataCols = createDataColumns(keys);

    return [actionCol, ...dataCols];
  }, [columns, rows, setEditingRow, setDeletingRow]);

  return (
    <CrudPanelProvider 
        stateValue={{ selectedTable, tableDetails, isFetching: rowsQuery.isFetching }} 
        actionsValue={{ setSelectedTable, onRefresh: fetchRows, onAddRow: () => setShowAddModal(true), setPage, setMutationError, setSuccessMessage }}
    >
      <div className='space-y-4'>
        <DataTable
            columnDefs={columnDefs}
            rows={rows}
            isLoadingRows={isLoadingRows}
            errorMessage={errorMessage}
            successMessage={successMessage}
            page={page}
            pageSize={pageSize}
            totalRows={totalRows}
        />
        {showAddModal && tableDetail && <RowFormModal columns={tableDetail.columns} mode='add' onSubmit={handleAdd} onClose={() => setShowAddModal(false)} isPending={crudMutation.isPending} />}
        {editingRow && tableDetail && <RowFormModal columns={tableDetail.columns} initialData={editingRow} mode='edit' onSubmit={handleEdit} onClose={() => setEditingRow(null)} isPending={crudMutation.isPending} />}
        <ConfirmModal isOpen={deletingRow !== null} onClose={() => setDeletingRow(null)} onConfirm={handleDelete} title='Delete Row' message='Are you sure?' confirmText='Delete' isDangerous={true} loading={crudMutation.isPending} />
      </div>
    </CrudPanelProvider>
  );
}

'use client';

import { TerminalSquareIcon, Table2Icon } from 'lucide-react';
import type { JSX } from 'react';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/shared/ui/primitives.public';
import { FormSection } from '@/shared/ui/forms-and-actions.public';
import { LoadingState, EmptyState } from '@/shared/ui/navigation-and-layout.public';
import { CrudPanel } from './CrudPanel';
import { SqlQueryConsole } from './SqlQueryConsole';
import { useDatabaseConfig, useDatabaseData } from '../context/DatabaseContext';

export function DatabaseOperationsTabs(): JSX.Element {
  const { dbType } = useDatabaseConfig();
  const { tableDetails, isLoading: previewLoading } = useDatabaseData();

  return (
    <Tabs defaultValue='sql' className='w-full'>
      <TabsList className='mb-4 border border-border/60 bg-card/30'>
        <TabsTrigger value='sql' className='gap-2 text-xs'>
          <TerminalSquareIcon className='size-3.5' />
          Command Console
        </TabsTrigger>
        <TabsTrigger value='crud' className='gap-2 text-xs'>
          <Table2Icon className='size-3.5' />
          Table Manager {tableDetails.length > 0 && `(${tableDetails.length})`}
        </TabsTrigger>
      </TabsList>

      <TabsContent value='sql'>
        <FormSection title='Command Console' className='p-5'>
          <SqlQueryConsole />
        </FormSection>
      </TabsContent>

      <TabsContent value='crud'>
        {previewLoading ? (
          <LoadingState
            message='Loading table metadata...'
            className='py-12 border border-border/60 bg-card/50 rounded-lg'
          />
        ) : tableDetails.length === 0 ? (
          <EmptyState
            title='No tables found'
            description={
              dbType === 'mongodb'
                ? 'Table metadata is not available for MongoDB. Use the command console tab for MongoDB operations.'
                : 'No tables found in the database.'
            }
            icon={<Table2Icon className='size-12 opacity-20' />}
          />
        ) : (
          <CrudPanel />
        )}
      </TabsContent>
    </Tabs>
  );
}

'use client';

import React, { useMemo, useState } from 'react';

import type { ModalStateProps } from '@/shared/contracts/ui/base';
import { SettingsPanelBuilder } from '@/shared/ui/templates/SettingsPanelBuilder';
import type { SettingsPanelField } from '@/shared/contracts/ui/settings';

interface RestoreModalProps extends ModalStateProps {
  backupName: string;
  onConfirm: (truncate: boolean) => void;
  title?: string;
  size?: 'sm' | 'md' | 'lg' | 'xl';
}

type RestoreFormState = {
  truncate: boolean;
};

export const RestoreModal = ({
  isOpen,
  onClose,
  onSuccess,
  backupName,
  onConfirm,
  title = 'Restore Database',
  size = 'sm',
}: RestoreModalProps): React.JSX.Element | null => {
  const [values, setValues] = useState<RestoreFormState>({ truncate: true });

  const fields = useMemo<SettingsPanelField<RestoreFormState>[]>(
    () => [
      {
        key: 'truncate',
        label: 'Confirmation',
        type: 'custom',
        render: () => (
          <p className='text-gray-300'>
            Are you sure you want to restore backup <strong>{backupName}</strong>?
          </p>
        ),
      },
      {
        key: 'truncate',
        label: 'Truncate (delete) existing data before restore',
        type: 'checkbox',
      },
    ],
    [backupName]
  );

  const handleSave = async (): Promise<void> => {
    onConfirm(values.truncate);
    onSuccess?.();
  };

  return (
    <SettingsPanelBuilder
      open={isOpen}
      onClose={onClose}
      title={title}
      fields={fields}
      values={values}
      onChange={(vals) => setValues((prev) => ({ ...prev, ...vals }))}
      onSave={handleSave}
      saveText='Restore'
      size={size}
    />
  );
};

'use client';

import type { JSX } from 'react';
import { StandardDataTablePanel } from '@/shared/ui/templates.public';
import { FileUploadButton } from '@/shared/ui/forms-and-actions.public';
import { Button } from '@/shared/ui/primitives.public';
import { useDatabaseBackupsStateContext, useDatabaseBackupsActionsContext } from '../../context/DatabaseBackupsContext';
import { useDatabaseColumns } from '../DatabaseColumns';
import type { FileUploadHelpers } from '@/shared/contracts/ui/base';

export function BackupDataTable(): JSX.Element {
  const { data, isLoading, isProd, backupRunNowAllowed, backupMaintenanceAllowed } =
    useDatabaseBackupsStateContext();
  const { handleBackup, handleUpload, handlePreviewCurrent } = useDatabaseBackupsActionsContext();
  const columns = useDatabaseColumns();
  const isRunBackupDisabled = isProd || !backupRunNowAllowed;
  const isUploadDisabled = isProd || !backupMaintenanceAllowed;

  const runBackupTitle = isRunBackupDisabled
    ? isProd
      ? 'Disabled in production'
      : 'Disabled by Database Engine operation controls'
    : undefined;
  const uploadTitle = isUploadDisabled
    ? isProd
      ? 'Disabled in production'
      : 'Disabled by Database Engine operation controls'
    : undefined;

  return (
    <StandardDataTablePanel
      data={data}
      columns={columns}
      isLoading={isLoading}
      onRefresh={handlePreviewCurrent}
      actions={
        <div className='flex flex-wrap items-center gap-2'>
          <Button
            disabled={isRunBackupDisabled}
            title={runBackupTitle}
            onClick={() => {
              void handleBackup().catch(() => {});
            }}
          >
            Run Backup
          </Button>
          <FileUploadButton
            accept='.archive'
            disabled={isUploadDisabled}
            title={uploadTitle}
            onFilesSelected={(files: File[], helpers?: FileUploadHelpers) => {
              handleUpload(files, helpers).catch(() => {});
            }}
          >
            Upload
          </FileUploadButton>
        </div>
      }
    />
  );
}

'use client';

import type { JSX } from 'react';
import { Button, Card, Input, Label, Switch } from '@/shared/ui/primitives.public';
import { FormField } from '@/shared/ui/forms-and-actions.public';
import { useDatabaseBackupsActionsContext, useDatabaseBackupsStateContext } from '../../context/DatabaseBackupsContext';

export function BackupSchedulerSettings(): JSX.Element {
  const {
    schedulerEnabledDraft,
    repeatTickEnabledDraft,
    activeTargetEnabledDraft,
    activeTargetTimeLocalDraft,
    activeTargetTimeLocalDraftValid,
    isBackupScheduleDirty,
    isBackupScheduleSaving,
  } = useDatabaseBackupsStateContext();

  const {
    handleSchedulerEnabledDraftChange,
    handleRepeatSchedulerTickDraftChange,
    handleActiveTargetEnabledDraftChange,
    handleActiveTargetTimeLocalChange,
    saveDailySchedule,
  } = useDatabaseBackupsActionsContext();

  return (
    <Card className='p-4 space-y-4 border-white/10 bg-gray-900/50'>
      <div className='flex items-center justify-between gap-3'>
        <Label htmlFor='database-backup-scheduler-enabled' className='font-medium text-white'>
          Scheduler
        </Label>
        <Switch
          id='database-backup-scheduler-enabled'
          checked={schedulerEnabledDraft}
          onCheckedChange={handleSchedulerEnabledDraftChange}
        />
      </div>

      {schedulerEnabledDraft && (
        <div className='space-y-4 pt-2'>
          <div className='flex items-center justify-between gap-3'>
            <Label htmlFor='database-backup-repeat-tick' className='text-sm text-white'>
              Repeat Tick
            </Label>
            <Switch
              id='database-backup-repeat-tick'
              checked={repeatTickEnabledDraft}
              onCheckedChange={handleRepeatSchedulerTickDraftChange}
            />
          </div>
          <div className='flex items-center justify-between gap-3'>
            <Label htmlFor='database-backup-active-target' className='text-sm text-white'>
              Active Target Enabled
            </Label>
            <Switch
              id='database-backup-active-target'
              checked={activeTargetEnabledDraft}
              onCheckedChange={handleActiveTargetEnabledDraftChange}
            />
          </div>
          <FormField label='Active Target Time (Local)'>
            <Input
              type='time'
              value={activeTargetTimeLocalDraft}
              onChange={(e) => handleActiveTargetTimeLocalChange(e.target.value)}
              className={!activeTargetTimeLocalDraftValid ? 'border-red-500' : ''}
            />
          </FormField>
          <Button
            onClick={saveDailySchedule}
            disabled={!isBackupScheduleDirty || isBackupScheduleSaving || !activeTargetTimeLocalDraftValid}
          >
            {isBackupScheduleSaving ? 'Saving...' : 'Save Schedule'}
          </Button>
        </div>
      )}
    </Card>
  );
}

'use client';

import { PlusIcon } from 'lucide-react';
import React, { useMemo } from 'react';

import type { LabeledOptionDto } from '@/shared/contracts/base';
import { Button } from '@/shared/ui/primitives.public';
import { SearchableSelect } from '@/shared/ui/forms-and-actions.public';

import {
  useCrudPanelActionsContext,
  useCrudPanelStateContext,
} from '../../context/CrudPanelContext';

export function DatabaseTableSelector(): React.JSX.Element {
  const { selectedTable, tableDetails, isFetching } = useCrudPanelStateContext();
  const { setSelectedTable, onRefresh, onAddRow, setPage, setMutationError, setSuccessMessage } =
    useCrudPanelActionsContext();
  const tableOptions = useMemo<Array<LabeledOptionDto<string>>>(
    () =>
      tableDetails.map((table) => ({
        value: table.name,
        label: `${table.name} (~${table.rowEstimate} rows)`,
      })),
    [tableDetails]
  );
  return (
    <div className='flex flex-wrap items-center gap-3'>
      <SearchableSelect
        value={selectedTable}
        onChange={(v) => {
          setSelectedTable(v ?? '');
          setPage(1);
          setMutationError(null);
          setSuccessMessage(null);
        }}
        options={tableOptions}
        placeholder='Select a table to manage...'
        className='min-w-[280px]'
      />

      {selectedTable && (
        <>
          <div className='h-4 w-px bg-border/60 mx-1' />
          <Button
            variant='outline'
            size='xs'
            onClick={onRefresh}
            disabled={isFetching}
            className='h-8'
            loading={isFetching}
          >
            Refresh
          </Button>
          <Button size='xs' onClick={onAddRow} className='h-8'>
            <PlusIcon className='size-3.5 mr-2' />
            Add Row
          </Button>
        </>
      )}
    </div>
  );
}

'use client';

import { ClockIcon, ChevronDownIcon, Trash2Icon } from 'lucide-react';
import React from 'react';

import { Button, Card } from '@/shared/ui/primitives.public';
import { cn } from '@/shared/utils/ui-utils';

export type SqlHistoryDropdownProps = {
  history: string[];
  showHistory: boolean;
  setShowHistory: (show: boolean) => void;
  onSelectQuery: (query: string) => void;
  onClearHistory: () => void;
};

export function SqlHistoryDropdown(props: SqlHistoryDropdownProps): React.JSX.Element {
  const { history, showHistory, setShowHistory, onSelectQuery, onClearHistory } = props;

  return (
    <div className='relative'>
      <Button
        variant='outline'
        size='sm'
        onClick={(): void => setShowHistory(!showHistory)}
        className='h-8 gap-1 text-xs'
        disabled={history.length === 0}
      >
        <ClockIcon className='size-3' />
        History ({history.length})
        <ChevronDownIcon
          className={cn('size-3 transition-transform', showHistory && 'rotate-180')}
        />
      </Button>
      {showHistory && history.length > 0 && (
        <Card
          variant='glass'
          padding='none'
          className='absolute right-0 top-full z-50 mt-1 w-96 max-h-64 overflow-hidden border-border bg-card/95 shadow-xl backdrop-blur-md'
        >
          <div className='flex items-center justify-between border-b border-white/5 px-3 py-2 bg-white/5'>
            <span className='text-[10px] uppercase font-bold text-gray-500 tracking-wider'>
              Recent queries
            </span>
            <Button
              variant='ghost'
              size='xs'
              onClick={(e) => {
                e.stopPropagation();
                onClearHistory();
              }}
              className='h-6 gap-1 text-[10px] text-red-400 hover:text-red-300 hover:bg-red-500/10'
            >
              <Trash2Icon className='size-3' />
              Clear
            </Button>
          </div>
          <div className='overflow-y-auto max-h-56 divide-y divide-white/5 custom-scrollbar'>
            {history.map((item: string, i: number) => (
              <Button
                key={i}
                variant='ghost'
                onClick={(): void => {
                  onSelectQuery(item);
                  setShowHistory(false);
                }}
                className='h-auto w-full justify-start rounded-none px-3 py-2.5 text-left text-xs font-mono text-gray-300 hover:bg-white/5 hover:text-white transition-colors'
                title={item}
              >
                <span className='truncate'>{item}</span>
              </Button>
            ))}
          </div>
        </Card>
      )}
    </div>
  );
}

import { z } from 'zod';

import {
  databaseEngineBackupScheduleSchema,
  databaseEngineBackupTargetScheduleSchema,
  databaseEngineOperationControlsSchema,
  databaseEnginePolicySchema,
  databaseEngineProviderSchema,
  databaseEngineServiceSchema,
} from '@/shared/contracts/database';
import { validationError } from '@/shared/errors/app-error';
import {
  DEFAULT_DATABASE_ENGINE_BACKUP_SCHEDULE,
  DEFAULT_DATABASE_ENGINE_OPERATION_CONTROLS,
  DEFAULT_DATABASE_ENGINE_POLICY,
  type DatabaseEngineBackupSchedule,
  type DatabaseEngineOperationControls,
  type DatabaseEnginePolicy,
  type DatabaseEngineProvider,
  type DatabaseEngineServiceRoute,
} from '@/shared/lib/db/database-engine-constants';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


const DATABASE_ENGINE_TIME_UTC_RE = /^([01]\d|2[0-3]):([0-5]\d)$/;

const isoDateStringSchema = z
  .string()
  .trim()
  .min(1)
  .refine((value: string): boolean => Number.isFinite(Date.parse(value)), {
    message: 'Expected ISO date string.',
  });

const nullableIsoDateStringSchema = isoDateStringSchema.nullable();

const databaseEnginePolicyStrictSchema = databaseEnginePolicySchema.strict();
const databaseEngineOperationControlsStrictSchema = databaseEngineOperationControlsSchema.strict();
const databaseEngineBackupTargetScheduleStrictSchema = databaseEngineBackupTargetScheduleSchema
  .extend({
    intervalDays: z.number().int().min(1).max(365),
    weekday: z.number().int().min(0).max(6),
    timeUtc: z.string().regex(DATABASE_ENGINE_TIME_UTC_RE),
    lastQueuedAt: nullableIsoDateStringSchema,
    lastRunAt: nullableIsoDateStringSchema,
    lastJobId: z.string().trim().min(1).nullable(),
    lastError: z.string().trim().min(1).nullable(),
    nextDueAt: nullableIsoDateStringSchema,
  })
  .strict();

const databaseEngineBackupScheduleStrictSchema = databaseEngineBackupScheduleSchema
  .extend({
    lastCheckedAt: nullableIsoDateStringSchema,
    mongodb: databaseEngineBackupTargetScheduleStrictSchema,
  })
  .strict();

const parseNonEmptyJsonObject = (
  raw: string | null | undefined,
  key: string
): Record<string, unknown> | null => {
  if (typeof raw !== 'string') return null;
  const trimmedRaw = raw.trim();
  if (!trimmedRaw) return null;

  let parsed: unknown;
  try {
    parsed = JSON.parse(trimmedRaw);
  } catch (error) {
    logClientError(error);
    throw validationError(`Invalid ${key} settings payload.`, {
      source: 'database_engine.settings',
      key,
      reason: 'invalid_json',
      cause: error instanceof Error ? error.message : 'unknown_error',
    });
  }

  if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
    throw validationError(`Invalid ${key} settings payload.`, {
      source: 'database_engine.settings',
      key,
      reason: 'invalid_shape',
    });
  }

  return parsed as Record<string, unknown>;
};

const parseWithSchema = <T>(
  key: string,
  raw: string | null | undefined,
  schema: z.ZodType<T>,
  fallback: T
): T => {
  const parsed = parseNonEmptyJsonObject(raw, key);
  if (!parsed) return fallback;

  const result = schema.safeParse(parsed);
  if (!result.success) {
    throw validationError(`Invalid ${key} settings payload.`, {
      source: 'database_engine.settings',
      key,
      reason: 'schema_validation_failed',
      issues: result.error.flatten(),
    });
  }

  return result.data;
};

export const parseDatabaseEnginePolicySetting = (
  raw: string | null | undefined
): DatabaseEnginePolicy =>
  parseWithSchema(
    'database engine policy',
    raw,
    databaseEnginePolicyStrictSchema,
    DEFAULT_DATABASE_ENGINE_POLICY
  );

export const parseDatabaseEngineOperationControlsSetting = (
  raw: string | null | undefined
): DatabaseEngineOperationControls =>
  parseWithSchema(
    'database engine operation controls',
    raw,
    databaseEngineOperationControlsStrictSchema,
    DEFAULT_DATABASE_ENGINE_OPERATION_CONTROLS
  );

export const parseDatabaseEngineBackupScheduleSetting = (
  raw: string | null | undefined
): DatabaseEngineBackupSchedule =>
  parseWithSchema(
    'database engine backup schedule',
    raw,
    databaseEngineBackupScheduleStrictSchema,
    DEFAULT_DATABASE_ENGINE_BACKUP_SCHEDULE
  );

export const parseDatabaseEngineServiceRouteMapSetting = (
  raw: string | null | undefined
): Partial<Record<DatabaseEngineServiceRoute, DatabaseEngineProvider>> => {
  const parsed = parseNonEmptyJsonObject(raw, 'database engine service route map');
  if (!parsed) return {};

  const result: Partial<Record<DatabaseEngineServiceRoute, DatabaseEngineProvider>> = {};
  Object.entries(parsed).forEach(([service, provider]: [string, unknown]): void => {
    const serviceValidation = databaseEngineServiceSchema.safeParse(service);
    if (!serviceValidation.success) {
      throw validationError('Invalid database engine service route map payload.', {
        source: 'database_engine.settings',
        key: 'database engine service route map',
        reason: 'invalid_service',
        service,
      });
    }
    const providerValidation = databaseEngineProviderSchema.safeParse(provider);
    if (!providerValidation.success) {
      throw validationError('Invalid database engine service route map payload.', {
        source: 'database_engine.settings',
        key: 'database engine service route map',
        reason: 'invalid_provider',
        service,
        provider,
      });
    }
    result[serviceValidation.data] = providerValidation.data;
  });

  return result;
};

export const parseDatabaseEngineCollectionRouteMapSetting = (
  raw: string | null | undefined
): Record<string, DatabaseEngineProvider> => {
  const parsed = parseNonEmptyJsonObject(raw, 'database engine collection route map');
  if (!parsed) return {};

  const result: Record<string, DatabaseEngineProvider> = {};
  Object.entries(parsed).forEach(([collection, provider]: [string, unknown]): void => {
    const normalizedCollection = collection.trim();
    if (!normalizedCollection) {
      throw validationError('Invalid database engine collection route map payload.', {
        source: 'database_engine.settings',
        key: 'database engine collection route map',
        reason: 'invalid_collection',
      });
    }
    const providerValidation = databaseEngineProviderSchema.safeParse(provider);
    if (!providerValidation.success) {
      throw validationError('Invalid database engine collection route map payload.', {
        source: 'database_engine.settings',
        key: 'database engine collection route map',
        reason: 'invalid_provider',
        collection: normalizedCollection,
        provider,
      });
    }
    result[normalizedCollection] = providerValidation.data;
  });

  return result;
};

'use client';

import { useCallback, useEffect, useMemo, useState } from 'react';
import type { DatabaseColumnInfo, DatabaseTableDetail, DatabaseType } from '@/shared/contracts/database';
import type { ListQuery } from '@/shared/contracts/ui/queries';
import { ApiError } from '@/shared/lib/api-client';
import { createListQueryV2 } from '@/shared/lib/query-factories-v2';
import { QUERY_KEYS } from '@/shared/lib/query-keys';
import { executeSqlQuery } from '../api';
import { useDatabaseConfig, useDatabaseData } from '../context/DatabaseContext';
import { useCrudMutations, type UseCrudMutationsReturn } from './crud/useCrudMutations';

type CrudRowsResult = {
  rows: Record<string, unknown>[];
  totalRows: number;
};

export interface UseCrudPanelStateReturn extends UseCrudMutationsReturn {
  selectedTable: string;
  setSelectedTable: (table: string) => void;
  page: number;
  setPage: (page: number) => void;
  pageSize: number;
  setPageSize: (size: number) => void;
  showAddModal: boolean;
  setShowAddModal: (show: boolean) => void;
  editingRow: Record<string, unknown> | null;
  setEditingRow: (row: Record<string, unknown> | null) => void;
  deletingRow: Record<string, unknown> | null;
  setDeletingRow: (row: Record<string, unknown> | null) => void;
  tableDetail: DatabaseTableDetail | undefined;
  rows: Record<string, unknown>[];
  totalRows: number;
  isLoadingRows: boolean;
  maxPage: number;
  fetchRows: () => void;
  dbType: DatabaseType;
  tableDetails: DatabaseTableDetail[];
  columns: DatabaseColumnInfo[];
  rowsQuery: ListQuery<CrudRowsResult, CrudRowsResult>;
}

export function useCrudPanelState(props: {
  tableDetails?: DatabaseTableDetail[];
  defaultTable?: string;
  dbType?: DatabaseType;
}): UseCrudPanelStateReturn {
  const dbKeys = QUERY_KEYS.system.databases;
  const { dbType: contextDbType } = useDatabaseConfig();
  const { tableDetails: contextTableDetails } = useDatabaseData();
  const dbType = props.dbType ?? contextDbType;
  const tableDetails = props.tableDetails ?? contextTableDetails;

  const [selectedTable, setSelectedTable] = useState(props.defaultTable ?? '');
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(20);
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingRow, setEditingRow] = useState<Record<string, unknown> | null>(null);
  const [deletingRow, setDeletingRow] = useState<Record<string, unknown> | null>(null);

  const mutations = useCrudMutations();

  const tableDetail = useMemo(
    () => tableDetails.find((t) => t.name === selectedTable),
    [tableDetails, selectedTable]
  );

  const rowsQuery = createListQueryV2<CrudRowsResult, CrudRowsResult>({
    queryKey: dbKeys.crudRows({ dbType, selectedTable, page, pageSize }),
    enabled: selectedTable !== '',
    queryFn: async () => {
      if (selectedTable === '') return { rows: [], totalRows: 0 };
      if (dbType !== 'mongodb') throw new ApiError('Only MongoDB CRUD operations are supported.', 400);

      const mongoResult = await executeSqlQuery({
        type: 'mongodb',
        collection: selectedTable,
        operation: 'find',
        filter: {},
      });

      if (mongoResult.error) throw new ApiError(mongoResult.error, 400);

      return {
        rows: mongoResult.rows,
        totalRows: mongoResult.rowCount ?? mongoResult.rows.length,
      };
    },
  });

  const fetchRows = useCallback(() => {
    if (selectedTable === '') return;
    mutations.setMutationError(null);
    mutations.setSuccessMessage(null);
    void rowsQuery.refetch();
  }, [rowsQuery, selectedTable, mutations]);

  const handleAdd = (data: Record<string, unknown>) => {
    mutations.handleAdd(selectedTable, data, () => {
      setShowAddModal(false);
      void rowsQuery.refetch();
    });
  };

  const handleEdit = (data: Record<string, unknown>) => {
    if (!editingRow) return;
    mutations.handleEdit(selectedTable, editingRow, data, () => {
      setEditingRow(null);
      void rowsQuery.refetch();
    });
  };

  const handleDelete = () => {
    if (!deletingRow) return;
    mutations.handleDelete(selectedTable, deletingRow, () => {
      setDeletingRow(null);
      void rowsQuery.refetch();
    });
  };

  return {
    ...mutations,
    selectedTable,
    setSelectedTable,
    page,
    setPage,
    pageSize,
    setPageSize,
    showAddModal,
    setShowAddModal,
    editingRow,
    setEditingRow,
    deletingRow,
    setDeletingRow,
    tableDetail,
    rows: rowsQuery.data?.rows ?? [],
    totalRows: rowsQuery.data?.totalRows ?? 0,
    isLoadingRows: rowsQuery.isLoading,
    maxPage: Math.ceil((rowsQuery.data?.totalRows ?? 0) / pageSize),
    fetchRows,
    handleAdd,
    handleEdit,
    handleDelete,
    dbType,
    tableDetails,
    columns: tableDetail?.columns ?? [],
    rowsQuery,
  };
}

'use client';

import { useRouter } from 'nextjs-toploader/app';
import { startTransition, useCallback, useEffect, useMemo, useRef, useState } from 'react';

import type { DatabaseBackupResponse, DatabaseInfo, DatabaseRestoreResponse, DatabaseType } from '@/shared/contracts/database';
import { useSettingsMap, useUpdateSetting } from '@/shared/hooks/use-settings';
import { isValidDatabaseEngineBackupTimeUtc } from '@/shared/lib/db/database-engine-backup-schedule';
import {
  DATABASE_ENGINE_BACKUP_SCHEDULE_KEY,
  DATABASE_ENGINE_OPERATION_CONTROLS_KEY,
  DEFAULT_DATABASE_ENGINE_BACKUP_SCHEDULE,
  DEFAULT_DATABASE_ENGINE_OPERATION_CONTROLS,
  type DatabaseEngineBackupType,
} from '@/shared/lib/db/database-engine-constants';
import { localHmToUtcHm, utcHmToLocalHm } from '@/shared/lib/db/utils/backup-schedule-time';
import type { FileUploadHelpers } from '@/shared/contracts/ui/base';
import { useToast } from '@/shared/ui/primitives.public';
import {
  logClientCatch,
  logClientError,
} from '@/shared/utils/observability/client-error-logger';

import {
  parseDatabaseEngineBackupScheduleSetting,
  parseDatabaseEngineOperationControlsSetting,
} from './database-engine-settings-parsing';
import {
  useCreateBackupMutation,
  useDatabaseBackups,
  useDeleteBackupMutation,
  useRestoreBackupMutation,
  useUploadBackupMutation,
} from '../hooks/useDatabaseQueries';

export function useDatabaseBackupsState() {
  const router = useRouter();
  const [activeTab, setActiveTab] = useState<DatabaseType>('mongodb');
  const [isLogModalOpen, setIsLogModalOpen] = useState(false);
  const [logModalContent, setLogModalContent] = useState('');
  const [isRestoreModalOpen, setIsRestoreModalOpen] = useState(false);
  const [selectedBackupForRestore, setSelectedBackupForRestore] = useState<string | null>(null);
  const [backupToDelete, setBackupToDelete] = useState<string | null>(null);
  const [schedulerEnabledDraft, setSchedulerEnabledDraft] = useState(false);
  const [repeatTickEnabledDraft, setRepeatTickEnabledDraft] = useState(false);
  const [activeTargetEnabledDraft, setActiveTargetEnabledDraft] = useState(false);
  const [activeTargetTimeLocalDraft, setActiveTargetTimeLocalDraft] = useState('02:00');

  const { toast } = useToast();
  const isProd = process.env['NODE_ENV'] === 'production';
  const settingsQuery = useSettingsMap({ scope: 'all' });
  const updateSetting = useUpdateSetting();
  const lastSettingsValidationSignatureRef = useRef<string | null>(null);

  const backupsQuery = useDatabaseBackups(activeTab);
  const data = useMemo(() => backupsQuery.data ?? [], [backupsQuery.data]);

  const createBackup = useCreateBackupMutation();
  const restoreBackup = useRestoreBackupMutation();
  const uploadBackup = useUploadBackupMutation();
  const deleteBackup = useDeleteBackupMutation();

  const readPayload = <T,>(result: { payload: T | unknown }): T => result.payload as T;

  const parsedSettings = useMemo(() => {
    const errors: string[] = [];
    const loggedErrors: unknown[] = [];

    const parseSetting = <T>(parser: () => T, fallback: T): T => {
      try {
        return parser();
      } catch (error) {
        logClientError(error);
        errors.push(error instanceof Error ? error.message : 'Invalid backup settings payload.');
        loggedErrors.push(error);
        return fallback;
      }
    };

    return {
      operationControls: parseSetting(
        () =>
          parseDatabaseEngineOperationControlsSetting(
            settingsQuery.data?.get(DATABASE_ENGINE_OPERATION_CONTROLS_KEY)
          ),
        DEFAULT_DATABASE_ENGINE_OPERATION_CONTROLS
      ),
      backupSchedule: parseSetting(
        () =>
          parseDatabaseEngineBackupScheduleSetting(
            settingsQuery.data?.get(DATABASE_ENGINE_BACKUP_SCHEDULE_KEY)
          ),
        DEFAULT_DATABASE_ENGINE_BACKUP_SCHEDULE
      ),
      errors,
      loggedErrors,
    };
  }, [settingsQuery.data]);

  const operationControls = parsedSettings.operationControls;
  const backupSchedule = parsedSettings.backupSchedule;
  const settingsValidationErrors = parsedSettings.errors;

  const backupRunNowAllowed = operationControls.allowManualBackupRunNow;
  const backupMaintenanceAllowed = operationControls.allowManualBackupMaintenance;
  const schedulerEnabled = backupSchedule.schedulerEnabled;
  const repeatSchedulerTickEnabled = backupSchedule.repeatTickEnabled;
  const isBackupScheduleSaving = updateSetting.isPending;
  const activeTargetKey: DatabaseEngineBackupType = 'mongodb';
  const activeTargetSchedule = backupSchedule[activeTargetKey];
  const activeTargetTimeLocalCurrent = useMemo(
    () => utcHmToLocalHm(activeTargetSchedule.timeUtc) ?? activeTargetSchedule.timeUtc,
    [activeTargetSchedule.timeUtc]
  );
  const activeTargetTimeLocalDraftValid = isValidDatabaseEngineBackupTimeUtc(
    activeTargetTimeLocalDraft
  );

  useEffect(() => {
    setSchedulerEnabledDraft(backupSchedule.schedulerEnabled);
    setRepeatTickEnabledDraft(backupSchedule.repeatTickEnabled);
    setActiveTargetEnabledDraft(activeTargetSchedule.enabled);
    setActiveTargetTimeLocalDraft(activeTargetTimeLocalCurrent);
  }, [
    backupSchedule.schedulerEnabled,
    backupSchedule.repeatTickEnabled,
    activeTargetSchedule.enabled,
    activeTargetTimeLocalCurrent,
  ]);

  useEffect(() => {
    if (parsedSettings.loggedErrors.length === 0) {
      lastSettingsValidationSignatureRef.current = null;
      return;
    }

    const signature = settingsValidationErrors.join('::');
    if (lastSettingsValidationSignatureRef.current === signature) return;
    lastSettingsValidationSignatureRef.current = signature;

    parsedSettings.loggedErrors.forEach((error: unknown): void => {
      logClientError(error, {
        context: {
          source: 'useDatabaseBackupsState',
          action: 'parsePersistedSettings',
        },
      });
    });

    toast(settingsValidationErrors[0] ?? 'Invalid database backup settings payload.', {
      variant: 'error',
    });
  }, [parsedSettings.loggedErrors, settingsValidationErrors, toast]);

  const isBackupScheduleDirty = useMemo(
    () =>
      schedulerEnabledDraft !== backupSchedule.schedulerEnabled ||
      repeatTickEnabledDraft !== backupSchedule.repeatTickEnabled ||
      activeTargetEnabledDraft !== activeTargetSchedule.enabled ||
      activeTargetTimeLocalDraft !== activeTargetTimeLocalCurrent,
    [
      schedulerEnabledDraft,
      backupSchedule.schedulerEnabled,
      repeatTickEnabledDraft,
      backupSchedule.repeatTickEnabled,
      activeTargetEnabledDraft,
      activeTargetSchedule.enabled,
      activeTargetTimeLocalDraft,
      activeTargetTimeLocalCurrent,
    ]
  );

  const openLogModal = useCallback((content: string): void => {
    setLogModalContent(content);
    setIsLogModalOpen(true);
  }, []);

  const closeLogModal = useCallback((): void => {
    setIsLogModalOpen(false);
    setLogModalContent('');
  }, []);

  const handleRestoreRequest = useCallback((backup: DatabaseInfo): void => {
    setSelectedBackupForRestore(backup.name);
    setIsRestoreModalOpen(true);
  }, []);

  const handleRestoreConfirm = async (truncate: boolean): Promise<void> => {
    const backupName = selectedBackupForRestore;
    setIsRestoreModalOpen(false);
    setSelectedBackupForRestore(null);

    if (!backupName) return;

    try {
      const result = await restoreBackup.mutateAsync({
        dbType: activeTab,
        backupName,
        truncateBeforeRestore: truncate,
      });
      const { ok } = result;
      const payload = readPayload<DatabaseRestoreResponse>(result);
      const log = String(payload.log ?? 'No log available.');

      if (ok) {
        openLogModal(
          `${payload.message ?? 'Backup restored successfully.'}

---LOG---
${log}`
        );
      } else {
        const meta = [
          payload.errorId ? `Error ID: ${payload.errorId}` : null,
          payload.stage ? `Stage: ${payload.stage}` : null,
          payload.backupName ? `Backup: ${payload.backupName}` : null,
        ]
          .filter(Boolean)
          .join('\n');

        openLogModal(
          `${payload.error ?? 'Failed to restore backup.'}${
            meta
              ? `

${meta}`
              : ''
          }

---LOG---
${log}`
        );
      }
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'DatabaseBackupsPanel',
        action: 'restoreBackup',
        backupName,
        dbType: activeTab,
      });
      openLogModal(`An error occurred during restoration.

${String(error)}`);
    }
  };

  const handleBackup = async (): Promise<void> => {
    try {
      const result = await createBackup.mutateAsync(activeTab);
      const { ok } = result;
      const payload = readPayload<DatabaseBackupResponse>(result);
      const log = String(payload.log ?? 'No log available.');
      if (ok) {
        if (payload.jobId) {
          toast(payload.message ?? `Database backup job queued (job: ${payload.jobId}).`, {
            variant: 'success',
          });
          return;
        }

        if (payload.warning) {
          openLogModal(`${payload.message ?? 'Backup created'}: ${payload.warning}

---LOG---
${log}`);
        } else {
          openLogModal(`${payload.message ?? 'Backup created successfully.'}

---LOG---
${log}`);
        }
      } else {
        openLogModal(`${payload.error ?? 'Failed to create backup.'}

---LOG---
${log}`);
      }
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'DatabaseBackupsPanel',
        action: 'createBackup',
        dbType: activeTab,
      });
      openLogModal(`An error occurred during backup.

${String(error)}`);
    }
  };

  const handleDeleteRequest = useCallback((backupName: string): void => {
    setBackupToDelete(backupName);
  }, []);

  const handleConfirmDelete = async (): Promise<void> => {
    if (!backupToDelete) return;
    try {
      const result = await deleteBackup.mutateAsync({
        dbType: activeTab,
        backupName: backupToDelete,
      });
      if (result.ok) {
        toast('Backup deleted successfully.', { variant: 'success' });
      } else {
        toast('Failed to delete backup.', { variant: 'error' });
      }
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'DatabaseBackupsPanel',
        action: 'deleteBackup',
        backupName: backupToDelete,
        dbType: activeTab,
      });
      toast('An error occurred during deletion.', { variant: 'error' });
    } finally {
      setBackupToDelete(null);
    }
  };

  const handleUpload = async (files: File[], helpers?: FileUploadHelpers): Promise<void> => {
    const file = files[0];
    if (!file) return;

    try {
      const result = await uploadBackup.mutateAsync({
        dbType: activeTab,
        file,
        onProgress: (loaded: number, total?: number) => helpers?.reportProgress(loaded, total),
      });
      if (result.ok) {
        toast('Backup uploaded successfully.', { variant: 'success' });
      } else {
        toast('Failed to upload backup.', { variant: 'error' });
      }
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'DatabaseBackupsPanel',
        action: 'uploadBackup',
        filename: file.name,
        dbType: activeTab,
      });
      toast('An error occurred during upload.', { variant: 'error' });
    }
  };

  const handlePreview = (backupName: string): void => {
    const url = `/admin/databases/preview?backup=${encodeURIComponent(backupName)}&type=${activeTab}`;
    startTransition(() => {
      router.push(url);
    });
  };

  const handlePreviewCurrent = (): void => {
    startTransition(() => {
      router.push(`/admin/databases/preview?mode=current&type=${activeTab}`);
    });
  };

  const handleSchedulerEnabledDraftChange = useCallback((enabled: boolean): void => {
    setSchedulerEnabledDraft(enabled);
  }, []);

  const handleRepeatSchedulerTickDraftChange = useCallback((enabled: boolean): void => {
    setRepeatTickEnabledDraft(enabled);
  }, []);

  const handleActiveTargetEnabledDraftChange = useCallback((enabled: boolean): void => {
    setActiveTargetEnabledDraft(enabled);
  }, []);

  const handleActiveTargetTimeLocalChange = useCallback((value: string): void => {
    setActiveTargetTimeLocalDraft(value);
  }, []);

  const saveDailySchedule = useCallback(async (): Promise<void> => {
    if (!isValidDatabaseEngineBackupTimeUtc(activeTargetTimeLocalDraft)) {
      toast('Backup time must be a valid HH:MM value.', { variant: 'error' });
      return;
    }

    const nextTimeUtc = localHmToUtcHm(activeTargetTimeLocalDraft);
    if (!nextTimeUtc) {
      toast('Failed to convert local backup time to UTC.', { variant: 'error' });
      return;
    }

    const activeTargetNext = {
      ...activeTargetSchedule,
      enabled: activeTargetEnabledDraft,
      cadence: 'daily' as const,
      intervalDays: 1,
      timeUtc: nextTimeUtc,
    };
    const nextSchedule = {
      ...backupSchedule,
      schedulerEnabled: schedulerEnabledDraft,
      repeatTickEnabled: repeatTickEnabledDraft,
      mongodb: activeTargetNext,
    };

    try {
      await updateSetting.mutateAsync({
        key: DATABASE_ENGINE_BACKUP_SCHEDULE_KEY,
        value: JSON.stringify(nextSchedule),
      });
      await settingsQuery.refetch();
      void fetch('/api/databases/engine/backup-scheduler/status', {
        method: 'GET',
        cache: 'no-store',
      });
      toast('Backup schedule saved.', { variant: 'success' });
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'DatabaseBackupsPanel',
        action: 'saveDailySchedule',
        setting: 'database_engine_backup_schedule_v1',
        dbType: activeTargetKey,
      });
      toast('Failed to save backup schedule.', { variant: 'error' });
    }
  }, [
    activeTargetTimeLocalDraft,
    toast,
    activeTargetSchedule,
    activeTargetEnabledDraft,
    activeTargetKey,
    backupSchedule,
    schedulerEnabledDraft,
    repeatTickEnabledDraft,
    updateSetting,
    settingsQuery,
  ]);

  return {
    activeTab,
    setActiveTab,
    isLogModalOpen,
    logModalContent,
    isRestoreModalOpen,
    selectedBackupForRestore,
    backupToDelete,
    setBackupToDelete,
    setIsRestoreModalOpen,
    setSelectedBackupForRestore,
    data,
    isLoading: backupsQuery.isFetching,
    isProd,
    backupRunNowAllowed,
    backupMaintenanceAllowed,
    schedulerEnabled,
    repeatSchedulerTickEnabled,
    schedulerEnabledDraft,
    repeatTickEnabledDraft,
    activeTargetEnabledDraft,
    activeTargetTimeLocalDraft,
    activeTargetTimeLocalDraftValid,
    isBackupScheduleDirty,
    activeTargetKey,
    isBackupScheduleSaving,
    settingsValidationErrors,
    closeLogModal,
    handleBackup,
    handleUpload,
    handleRestoreRequest,
    handleRestoreConfirm,
    handleDeleteRequest,
    handleConfirmDelete,
    handlePreview,
    handlePreviewCurrent,
    handleSchedulerEnabledDraftChange,
    handleRepeatSchedulerTickDraftChange,
    handleActiveTargetEnabledDraftChange,
    handleActiveTargetTimeLocalChange,
    saveDailySchedule,
  };
}

