export function useRestoreBackupMutation(): MutationResult<
  ApiPayloadResult<DatabaseRestoreResponse>,
  { dbType: DatabaseType; backupName: string; truncateBeforeRestore: boolean }
  > {
  const mutationKey = dbKeys.all;
